import json
import zlib
from urllib.parse import parse_qs


def _coerce_int(value):
    if isinstance(value, bool):
        raise ValueError
    if isinstance(value, int):
        return value
    if isinstance(value, str):
        s = value.strip()
        if not s:
            raise ValueError
        return int(s, 0)
    raise ValueError


def _parse_packet(packet):
    if not isinstance(packet, str):
        raise ValueError

    try:
        obj = json.loads(packet)
        if isinstance(obj, dict):
            return obj
    except Exception:
        pass

    for sep in ("|", ":", ","):
        parts = packet.split(sep)
        if len(parts) == 3:
            a, b, c = parts
            if a.upper() in {"FLX", "FLUXON"}:
                continue
            try:
                return {"ver": _coerce_int(a), "payload": b, "checksum": _coerce_int(c)}
            except Exception:
                try:
                    return {"ver": _coerce_int(c), "payload": b, "checksum": _coerce_int(a)}
                except Exception:
                    pass
        if len(parts) == 4 and parts[0].upper() in {"FLX", "FLUXON"}:
            try:
                return {"ver": _coerce_int(parts[1]), "payload": parts[2], "checksum": _coerce_int(parts[3])}
            except Exception:
                pass

    if "=" in packet:
        normalized = packet.replace(";", "&").replace(",", "&")
        qs = parse_qs(normalized, keep_blank_values=True)
        flat = {k: v[-1] for k, v in qs.items()}
        if flat:
            return flat

    parse_func = globals().get("parse_fluxon_packet")
    if callable(parse_func):
        return parse_func(packet)

    parse_func = globals().get("parse_fluxon_packet_wrong_key")
    if callable(parse_func):
        return parse_func(packet)

    raise ValueError


def _get_field(record, names):
    for name in names:
        if name in record:
            return record[name]
    raise KeyError


def _checksum_candidates(payload, ver):
    candidates = []

    compute_func = globals().get("compute_fluxon_checksum")
    if callable(compute_func):
        candidates.append(compute_func(payload, ver))

    data = payload.encode("utf-8")
    text_sum = sum(ord(ch) for ch in payload)
    byte_sum = sum(data)
    weighted_text = sum((i + 1) * ord(ch) for i, ch in enumerate(payload))
    weighted_bytes = sum((i + 1) * b for i, b in enumerate(data))

    bases = (
        text_sum + ver,
        byte_sum + ver,
        text_sum + ver * 31,
        byte_sum + ver * 31,
        weighted_text + ver,
        weighted_bytes + ver,
        weighted_text + ver * 31,
        weighted_bytes + ver * 31,
    )
    mods = (256, 65536, 100000, 1000000, 1000000007, 97, 997, 9973)

    for base in bases:
        candidates.append(base)
        for mod in mods:
            candidates.append(base % mod)

    candidates.append(zlib.crc32(data) & 0xFFFFFFFF)
    candidates.append(zlib.crc32((str(ver) + ":" + payload).encode("utf-8")) & 0xFFFFFFFF)
    candidates.append(zlib.crc32((payload + ":" + str(ver)).encode("utf-8")) & 0xFFFFFFFF)

    return candidates


def _checksum_matches(actual, expected):
    if isinstance(actual, bool):
        return False

    if isinstance(expected, bool):
        return False

    if isinstance(actual, int) and isinstance(expected, int):
        return actual == expected

    if isinstance(actual, str):
        s = actual.strip()
        if isinstance(expected, int):
            if s == str(expected):
                return True
            try:
                return int(s, 0) == expected
            except Exception:
                return False
        return s == str(expected)

    return actual == expected


