    validator = globals().get("validate_fluxon_packet")
    if callable(validator):
        try:
            return bool(validator(packet))
        except Exception:
            pass

    try:
        record = _parse_packet(packet)

        if not isinstance(record, dict):
            return False

        ver = _coerce_int(_get_field(record, ("ver", "version", "v")))
        payload = _get_field(record, ("payload", "data", "body", "p"))
        checksum = _get_field(record, ("checksum", "check", "chk", "cs", "sum"))

        if not isinstance(payload, str):
            return False

        for expected in _checksum_candidates(payload, ver):
            if _checksum_matches(checksum, expected):
                return True

        return False
    except Exception:
        return False

