import ast
import json
import re
from typing import Any


_DEFAULT_VERSION_MODULUS = {
    0: 89,
    1: 89,
    2: 97,
    3: 101,
    4: 103,
    5: 107,
    6: 109,
    7: 113,
    8: 127,
    9: 131,
    10: 137,
}


def _token_value(token: str) -> int:
    return (ord(token[0]) - ord("A") + 1) * 10 + int(token[1])


def _tokens_total(tokens: list[str]) -> int:
    return sum(_token_value(t) for t in tokens)


def _parse_literal_packet(packet: str) -> Any:
    try:
        return json.loads(packet)
    except Exception:
        pass
    try:
        return ast.literal_eval(packet)
    except Exception:
        return None


def _extract_int(value: Any) -> int | None:
    if value is None:
        return None
    if isinstance(value, bool):
        return int(value)
    if isinstance(value, int):
        return value
    m = re.search(r"-?\d+", str(value))
    return int(m.group(0)) if m else None


def _extract_tokens(value: Any) -> list[str]:
    if value is None:
        return []
    if isinstance(value, (list, tuple)):
        out: list[str] = []
        for item in value:
            if isinstance(item, str) and re.fullmatch(r"[A-Z]\d", item):
                out.append(item)
            else:
                out.extend(re.findall(r"[A-Z]\d", str(item)))
        return out
    return re.findall(r"[A-Z]\d", str(value))


