    if isinstance(literal, dict):
        version = _extract_int(
            literal.get("version", literal.get("ver", literal.get("v")))
        )
        checksum = _extract_int(
            literal.get("checksum", literal.get("check", literal.get("sum")))
        )
        if "tokens" in literal:
            tokens = _extract_tokens(literal.get("tokens"))
        else:
            tokens = _extract_tokens(literal.get("payload", ""))
        return {
            "version": 1 if version is None else version,
            "tokens": tokens,
            "checksum": checksum,
        }

