import re
import json
from typing import Any, Iterable


def _token_value(token: str) -> int:
    if len(token) != 2 or token[0] not in "ABCDEFG" or not token[1].isdigit():
        raise ValueError(f"Invalid Fluxon token: {token!r}")
    return int(token[1])


def _normalize(raw: float, channel: str) -> float:
    channel = channel.lower()
    if channel == "alpha":
        return raw / 100.0
    if channel == "beta":
        return raw / 10.0
    return raw


def _flatten_tokens(value: Any) -> list[str]:
    if value is None:
        return []
    if isinstance(value, str):
        return re.findall(r"(?<![A-Za-z0-9])[A-G][0-9](?![A-Za-z0-9])", value)
    if isinstance(value, dict):
        tokens = []
        for v in value.values():
            tokens.extend(_flatten_tokens(v))
        return tokens
    if isinstance(value, Iterable) and not isinstance(value, (bytes, bytearray)):
        tokens = []
        for v in value:
            tokens.extend(_flatten_tokens(v))
        return tokens
    return []


def _parse_packet(packet: str) -> tuple[str, list[str]]:
    text = packet.strip()

    try:
        obj = json.loads(text)
        if isinstance(obj, dict):
            channel = str(obj.get("channel", obj.get("Channel", ""))).lower()
            payload = obj.get("payload", obj.get("Payload", obj.get("tokens", obj.get("Tokens", ""))))
            tokens = _flatten_tokens(payload)
            if channel and tokens:
                return channel, tokens
    except Exception:
        pass

    channel_match = re.search(r"(?i)(?:^|[^A-Za-z])(alpha|beta|gamma|delta)(?:[^A-Za-z]|$)", text)
    channel = channel_match.group(1).lower() if channel_match else ""

    payload = text
    payload_match = re.search(r"(?i)payload\s*[:=]\s*(.*)", text)
    if payload_match:
        payload = payload_match.group(1)
    elif channel_match:
        start, end = channel_match.span(1)
        left = text[:start]
        right = text[end:]
        payload = right if re.search(r"[A-G][0-9]", right) else left

    tokens = re.findall(r"(?<![A-Za-z0-9])[A-G][0-9](?![A-Za-z0-9])", payload)
    if not tokens:
        tokens = re.findall(r"[A-G][0-9]", payload)

    return channel, tokens


def solve(packet: str) -> float:
    channel, tokens = _parse_packet(packet)
    if not tokens:
        raise ValueError("Packet payload contains no valid tokens")

    avg = sum(_token_value(token) for token in tokens) / len(tokens)
    return _normalize(avg, channel)

