import re
from typing import Any


def _to_int(value: Any):
    if isinstance(value, bool):
        return None
    if isinstance(value, int):
        return value
    if isinstance(value, str):
        s = value.strip().strip('"').strip("'")
        m = re.fullmatch(r"[vV](\d+)", s)
        if m:
            return int(m.group(1))
        try:
            return int(s, 0)
        except Exception:
            return None
    return None


def _records_from_mapping(obj: dict):
    ver = None
    payload = None
    checksum = None

    for k in ("ver", "version", "v"):
        if k in obj:
            ver = _to_int(obj[k])
            break

    for k in ("payload", "data", "body"):
        if k in obj:
            payload = obj[k]
            break

    for k in ("checksum", "check", "csum", "sum"):
        if k in obj:
            checksum = obj[k]
            break

    if ver is not None and payload is not None and checksum is not None:
        yield {"ver": ver, "payload": str(payload), "checksum": checksum}


def _parse_records(packet: str):
    if not isinstance(packet, str):
        return

    s = packet.strip()
    if not s:
        return

    try:
        obj = json.loads(s)
        if isinstance(obj, dict):
            yield from _records_from_mapping(obj)
    except Exception:
        pass

    pairs = {}
    for m in re.finditer(r"([A-Za-z_][A-Za-z0-9_]*)\s*=\s*([^|:;,#\s]+)", s):
        pairs[m.group(1).lower()] = m.group(2)
