    for sep in ("|", ":", ";", ",", "#", "~"):
        if sep not in s:
            continue
        parts = [p.strip() for p in s.split(sep)]

        if parts and parts[0].lower() in {"flx", "fluxon", "packet"}:
            parts = parts[1:]

        if len(parts) < 3:
            continue

        if len(parts) == 3:
            ranges = [parts]
        else:
            ranges = [parts[-3:], parts[:3]]

        for fields in ranges:
            for vi in range(3):
                for ci in range(3):
                    if vi == ci:
                        continue
                    pi = 3 - vi - ci
                    ver = _to_int(fields[vi])
                    checksum = fields[ci]
                    if ver is not None:
                        yield {"ver": ver, "payload": fields[pi], "checksum": checksum}


def _checksum_values(payload: str, ver: int):
    total = sum(ord(ch) for ch in payload)
    weighted = sum((i + 1) * ord(ch) for i, ch in enumerate(payload))

    bases = {
        total,
        total + ver,
        total * ver,
        total ^ ver,
        weighted,
        weighted + ver,
        weighted * ver,
        weighted ^ ver,
    }

    mods = (97, 100, 127, 251, 255, 256, 1000, 10000, 65535, 65536, 1000000007)

    vals = set(bases)
    for b in bases:
        for m in mods:
            vals.add(b % m)
    return vals


def _checksum_matches(payload: str, ver: int, checksum: Any) -> bool:
    vals = _checksum_values(payload, ver)
    n = _to_int(checksum)

    if n is not None:
        return n in vals

    if not isinstance(checksum, str):
        return False

    s = checksum.strip().strip('"').strip("'").lower()
    for v in vals:
        if s == str(v) or s == format(v, "x") or s == format(v, "02x"):
            return True
    return False


def solve(packet: str) -> bool:
    for record in _parse_records(packet):
        ver = record.get("ver")
        payload = record.get("payload")
        checksum = record.get("checksum")

        if not isinstance(ver, int) or ver <= 0 or ver > 9:
            continue
        if not isinstance(payload, str):
            continue
        if not _checksum_matches(payload, ver, checksum):
            continue

        if not payload:
            return False

        tokens = payload.split("-")
        return len(tokens) != len(set(tokens))

    return False

