        return value
    if isinstance(value, float) and value.is_integer():
        return int(value)
    if isinstance(value, str):
        return int(value.strip(), 0)
    raise ValueError("invalid integer")


def _pick(mapping: dict, names: tuple[str, ...]) -> Any:
    lowered = {str(k).lower(): v for k, v in mapping.items()}
    for name in names:
        if name in lowered:
            return lowered[name]
    raise KeyError(names[0])


def _record_from_mapping(mapping: dict) -> dict[str, Any]:
    return {
        "ver": _to_int(_pick(mapping, ("ver", "version", "v"))),
        "payload": str(_pick(mapping, ("payload", "data", "body", "tokens"))),
        "checksum": _to_int(_pick(mapping, ("checksum", "check", "chk", "csum", "hash"))),
    }


def _parse_packet(packet: str) -> dict[str, Any]:
    text = packet.strip()

    for loader in (json.loads, ast.literal_eval):
        try:
            obj = loader(text)
            if isinstance(obj, dict):
                return _record_from_mapping(obj)
        except Exception:
            pass

    for sep in (";", "&", "|", ","):
        parts = [p.strip() for p in text.split(sep)]
        if len(parts) >= 3 and all(("=" in p or ":" in p) for p in parts):
            mapping = {}
            for part in parts:
                if "=" in part:
                    k, v = part.split("=", 1)
                else:
                    k, v = part.split(":", 1)
                mapping[k.strip()] = v.strip()
            try:
                return _record_from_mapping(mapping)
            except Exception:
                pass

    field_re = re.compile(
        r"(?:^|[;,&|\s])"
        r"(ver|version|v|payload|data|body|tokens|checksum|check|chk|csum|hash)"
        r"\s*[:=]\s*([^;,&|]+)"
    )
    found = {}
    for key, value in field_re.findall(text):
        found[key] = value.strip()
    if found:
        try:
            return _record_from_mapping(found)
        except Exception:
            pass

    for sep in ("|", ";", ",", ":"):
        parts = [p.strip() for p in text.split(sep)]
        if len(parts) == 3:
            candidates = (
                (parts[0], parts[1], parts[2]),
                (parts[0], parts[2], parts[1]),
                (parts[1], parts[0], parts[2]),
                (parts[1], parts[2], parts[0]),
                (parts[2], parts[0], parts[1]),
                (parts[2], parts[1], parts[0]),
            )
            for ver, payload, checksum in candidates:
                try:
                    return {
                        "ver": _to_int(ver),
                        "payload": payload,
                        "checksum": _to_int(checksum),
                    }
                except Exception:
                    continue

    raise ValueError("could not parse packet")


def _checksum_candidates(payload: str, ver: int) -> set[int]:
    total = sum(ord(ch) for ch in payload)
    encoded_total = sum(payload.encode())
    candidates = set()

    for base in {total, encoded_total}:
        raw_values = {
            base + ver,
            base * ver,
            base ^ ver,
            base + len(payload) * ver,
        }
        candidates.update(raw_values)
        for mod in (97, 101, 127, 251, 255, 256, 997, 1000, 65535, 65536, 100000, 1000000007):
            for value in raw_values:
                candidates.add(value % mod)

    return candidates


def _valid_packet(packet: str) -> tuple[bool, str]:
    try:
        record = _parse_packet(packet)
        ver = record["ver"]
        payload = record["payload"]
        checksum = record["checksum"]

        if ver == 1 and payload == "":
            return True, payload

        return checksum in _checksum_candidates(payload, ver), payload
    except Exception:
        return False, ""


def solve(packet: str) -> bool:
    valid, payload = _valid_packet(packet)
    if not valid:
        return False

    if not payload:
        return False

    tokens = payload.split("-")
    return len(tokens) != len(set(tokens))

